var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"어린 시절, 우리 가족은 사람이 없는 깊은 산 속으로 들어갔다.","JPN":"幼い頃、僕の家族は人が誰もいない、深い山奥に移り住んだ。","ENG":"When I was young, our family fled deep into the mountains.","TWN":"小時候，我和家人住進了沒有人煙的深山裡。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"전쟁을 피해. 번뇌를 피해.","JPN":"戦争から、煩悩から逃れるために。","ENG":"We fled from the war. We fled from agony.","TWN":"為了避開戰爭，避開煩惱。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 핏줄에 얽힌 주박을 피해.","JPN":"そして血筋に刻まれた呪縛から逃れるために。","ENG":"And from the bounds of our bloodline.","TWN":"還有避開糾纏於血脈之中的束縛。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"때때로 정신이 온전한 날이면 어머니는 마루에 앉아 눈 내리는 하늘을 올려다보셨고.","JPN":"時々精神が正気に戻ると、母さんは床に座って雪が降る空を見上げていて。","ENG":"Whenever my mother was back to her senses, she would sit on the wooden floor and look up at the snowing sky.","TWN":"母親在偶爾清醒的日子裡，會坐在廊簷下，仰望著落雪的天空。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"나는 기둥 뒤에 숨어 그 야윈 등을 멀리서 바라보았다.","JPN":"僕は柱の裏に隠れて、その瘦せこけた背中を遠くから見つめていた。","ENG":"I would hide behind the pillars and watch her scrawny, bony back from afar.","TWN":"我就躲在柱子的後面，遠遠地望著母親瘦削的背影。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"바라만 볼 수밖에 없었다.","JPN":"見つめることしかできなかった。","ENG":"That was the only thing I could do.","TWN":"我只能遠遠地望著。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"미나 양……?","JPN":"ミナさん……？","ENG":"Mina...?","TWN":"米娜……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배? 깨어났구나!","JPN":"先輩？　目が覚めたんだね！","ENG":"Shiyoon? You’re awake!","TWN":"前輩？你醒了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"정신이 들어, 시윤 선배? 몸은 좀 어때?","JPN":"気が付いた、アキヤマ先輩？　身体の調子はどう？","ENG":"How are you feeling, Shiyoon? Any pain?","TWN":"你醒了，時雲前輩？感覺身體怎麼樣？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"으음……. 네. 괜찮은 것 같네요.","JPN":"うーん……はい。大丈夫そうです。","ENG":"Mmm... Yes. I'm fine, I think.","TWN":"呃嗯……嗯，好像沒事了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그러니 이제 업어 주시진 않아도 됩니다.","JPN":"ですから、もう背負ってもらわなくても大丈夫です。","ENG":"You can stop carrying me now.","TWN":"你不用背著我也行。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어, 어어. 응. 미안.","JPN":"あ、ああ。うん。ごめん。","ENG":"O-oh, right. Sorry about that.","TWN":"喔，喔喔，對不起……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그나저나 제가 얼마나 기절해 있었던 거죠?","JPN":"ところで、僕はどれくらい気絶していたんですか？","ENG":"Anyway, how long was I out?","TWN":"對了，我昏迷多久了？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"잘 모르겠어. 꽤 오랫동안이었지, 아마.","JPN":"よくわからない。随分長かったかな、たぶん。","ENG":"I'm not sure. Quite some time, probably.","TWN":"不知道，很久了吧，大概。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"어쨌든 일어나서 다행이야.","JPN":"とにかく起きてくれてよかったわ。","ENG":"I'm just glad that you're up again.","TWN":"不管怎樣，你能醒過來就好。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"미나가 선배 안 일어나면 어떡하냐고 계속 안절부절못했거든.","JPN":"ミナが、先輩が目を覚ましてくれなかったらどうしようって、すごく心配していたからね。","ENG":"Mina almost lost it, worrying over you not waking up.","TWN":"米娜一直很擔心你啦，說前輩醒不過來該怎麼辦。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"내가 언제!?","JPN":"そ、そんなこと言ってない！","ENG":"I did not!","TWN":"我哪有！？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 그래도 어떻게든 도박이 성공한 모양이네요.","JPN":"ハハ、ともかく、博打はなんとか成功したようですね。","ENG":"Ha ha, I guess our little move was worth the risk.","TWN":"哈哈，不管怎樣，看來我們賭贏了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"죽기 전의 발악이란 심정이었는데 말이죠.","JPN":"死ぬ前の悪あがきという気持ちでやりましたけどね。","ENG":"Even though it was out of desperation.","TWN":"當時就是垂死掙扎的心態。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"……선배 덕분이야. 나랑 서윤뿐이었으면 꼼짝없이 당했을걸.","JPN":"……先輩のおかげだよ。私とシズカだけだったら、あのままやられてた。","ENG":"...It's all thanks to you. If it weren’t for you, Seo Yoon and I would have been dead already.","TWN":"……這都多虧了前輩。要是只有我和徐芸，大概就只能等死了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"하아…….","JPN":"はぁ……","ENG":"*Sigh...*","TWN":"唉……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그렇게 매번 챙겨 주고 아무렇지 않은 척 웃어 넘긴 거지?","JPN":"毎回そうやって助けてあげて、何事もなかったように笑って過ごしていたんでしょ？","ENG":"So you've been protecting others this whole time, laughing it off?","TWN":"你每次都那麼照顧她，然後還若無其事地一笑置之吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"미나가 왜 여태 물경력인지 알 만하네.","JPN":"ミナのキャリアがと実力が釣り合わなかった理由がわかる気がするわね。","ENG":"No wonder why Mina is such an amateur, despite all these years.","TWN":"不難理解米娜為什麼到現在為止都還這麼菜了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"누, 누가 물경력이라는 거야?","JPN":"わ、私のキャリアのどこがよ！","ENG":"W-who are you calling amateur?!","TWN":"你，你說誰菜呢？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그런데 지금 두 분은 어디로 가시던 거죠?","JPN":"ところで、お二人はどこに行こうとしていたんですか？","ENG":"Where were you headed to, by the way?","TWN":"咳，所以我們現在要去哪裡？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"허신을 상대할 때 만났던 조난자 기억해?","JPN":"虚神の相手をしていたときに現れた遭難者を覚えてる？","ENG":"Do you remember the castaway we saw during the battle with the Hollow God?","TWN":"你還記得我們在對付幻神時碰到的那個遇難者嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그 애가 가르쳐 줬어. 클리포트 게임을 멈추려면 이 방향으로 가라고.","JPN":"その子が教えてくれたの。クリフォトゲームを止めたければ、この方向に進んでいけばいいって。","ENG":"She told us that we should go this way if we want to stop the Qliphoth Game.","TWN":"她告訴我，要想停止逆卡巴拉遊戲，就往這個方向走。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"통신도 먹통이라 다른 방법도 없었거든.","JPN":"通信もできなくなっていたし、他に方法はなかったから。","ENG":"All of our comm devices are jammed. There was really no other way.","TWN":"通訊斷了，又沒有其他辦法。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"조난자라…… 역시 그랬군요.","JPN":"遭難者……やはりそうでしたか。","ENG":"Castaway... So it all adds up.","TWN":"遇難者啊……果然如此。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"왜? 뭐 짐작 가는 거 있어?","JPN":"うん？　何か心当たりがあるの？","ENG":"What? You got any idea what might be going on?","TWN":"怎麼？你想到什麼了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"아뇨. 누군가의 도움은 받았을 거라고 생각했습니다.","JPN":"いいえ。誰かの助力があっただろうとは予想していました。","ENG":"No. I did infer that you would have gotten help from someone else, though.","TWN":"沒有，我在想你們應該是得到了誰的幫助吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"제 기량만으로 그 상황에서 두 분 모두 안전하게 보호할 확률은 희박했으니까요.","JPN":"僕の実力だけでは、あの状況でお二人を安全に保護できる確率はほとんどありませんでしたから。","ENG":"My chances of protecting you both in that situation were very low.","TWN":"在那種情況下，僅憑我自己的能力，保護你們周全的機率微乎其微。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하필 그런 무서운 분께 두 번이나 빚을 질 줄은 몰랐지만요, 하하.","JPN":"しかし、まさかあんな怖い方から二度も恩を買わされることになるなんてね、ハハ。","ENG":"I just didn't expect to be in debt twice to someone that terrifying. Ha ha.","TWN":"沒想到偏偏欠了那麼可怕的人二次人情，哈哈。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배까지 그 애를 괴물 취급 하는 거야?","JPN":"先輩まであの子を化け物扱いするの？","ENG":"You talk as if she's a monster, Shiyoon.","TWN":"前輩也把那個孩子當作怪物啊？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"희한하네. 내 눈에는 그냥 뻐기기 좋아하는 꼬마 같던데…….","JPN":"おかしいな。私からすればただの威張ってるお嬢ちゃんにしか見えなかったんだけど。","ENG":"Strange. She seemed nothing more than just a boastful kid...","TWN":"真稀奇，在我看來，她就是一個小屁孩……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"얘는 순진한 건지 모자란 건지 모르겠다니까.","JPN":"あなたって純粋なんだか、馬鹿なんだか。","ENG":"Sometimes, I can't tell if she's innocent or dumb.","TWN":"呼……真不知道是單純還是傻……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"뭐, 그래서 결국엔 보다시피 하염없이 걷는 중이었어.","JPN":"まぁそれで、とにかく見ての通りただひたすら歩いていたというわけ。","ENG":"Well, that’s why we're walking towards nowhere.","TWN":"總之，現在如你所見，我們也不知道終點有什麼。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"咳嗯……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"큰일이네…….","JPN":"参ったわね……","ENG":"This isn't good...","TWN":"現在很不妙呢……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"가도 가도 끝이 안 나. 가지고 있는 식량이라고 해 봤자 셋이서 한 끼 먹기도 부족한데.","JPN":"いくら進んでも終わりがない。持っている食料って言っても、三人で食べる一食分もないし。","ENG":"The road never seems to end. We don’t even have enough ration to last one meal.","TWN":"走也走不到盡頭。雖然還有些糧食，但是都不夠我們三個人吃一頓的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"확실히 곤란한 일이네요.","JPN":"確かに、それは困りましたね。","ENG":"A problem indeed.","TWN":"確實很麻煩。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"다른 분들과 통신은 되던가요?","JPN":"他の皆さんと通信は繋がりましたか？","ENG":"How is the comms working out?","TWN":"和其他人的通訊恢復了嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"계속 시도는 하고 있는데……. 솔직히 가망이 없어 보여.","JPN":"ずっと試してはいるんだけど……正直難しそう。","ENG":"We're trying... but at this point, I think it's hopeless.","TWN":"我一直在嘗試……不過說實話，看起來沒什麼希望。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"엔터프라이즈도, 코핀도. 애초에 우리가 지금 어느 좌표에 있는지도 모를 거 아냐?","JPN":"エンタープライズもコフィンも。そもそも私たちの今の座標すら知らないじゃない？","ENG":"Neither Enterprise nor Coffin is picking up. They have no idea where we are.","TWN":"企業號、科芬，就算是他們也不知道我們現在的座標吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Huh?","TWN":"呃？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"왜 그래, 유미나?","JPN":"どうしたの、ミナ？","ENG":"What's wrong, Yoo Mina?","TWN":"怎麼了，劉米娜？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저기…… 지평선 끝에. 뭔가 있어.","JPN":"あの……地平線の先に、何かがある。","ENG":"There... over the horizon. There's something there.","TWN":"那邊……遠處地平線的盡頭，有什麼東西。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"으음. 잘 안 보여. 너무 먼데.","JPN":"うーん。よく見えない。遠すぎるわ。","ENG":"Mmm. I can't see. It's too far.","TWN":"呃嗯，看不清楚，太遠了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"선배는 어때? 뭔지 알겠어?","JPN":"先輩はどう？　何かわかる？","ENG":"What about you, Shiyoon? Do you see anything?","TWN":"前輩呢？知道是什麼嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"아뇨. 저에게도 흐릿하게만 보이네요. 가까이 가서 확인하는 게 어떨까요?","JPN":"いいえ。僕にも微かにしか見えませんね。近くまで行って確認してみましょうか？","ENG":"No. I can barely make out the silhouette. Why don't we go closer and find out?","TWN":"不知道，我看著也很模糊。靠近確認一下怎麼樣？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"괜찮겠어, 선배?","JPN":"いいの、先輩？","ENG":"Will you be okay, Shiyoon?","TWN":"沒問題嗎，前輩？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"어디서 적이 나타날지 모르잖아. 깨어난 지도 얼마 안 됐으면서.","JPN":"またどこから敵が現れるかわからないでしょ。意識は戻ったばかりだし。","ENG":"We don't know what danger we're getting ourselves into. Besides, you've just regained consciousness.","TWN":"敵人說不定就會從哪裡冒出來，你才醒過來沒多久。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"조난자가 말했다고 하셨죠? <color=#ffd34c>클리포트 게임을 멈추려면</color>이라고.","JPN":"遭難者が言っていたんですよね？<color=#ffd34c>クリフォトゲームを止めたければ</color>、と。","ENG":"The castaway mentioned something like... <color=#ffd34c>stopping the Qliphoth Game</color>, right?","TWN":"米娜你說的遇難者，提到了<color=#ffd34c>停止逆卡巴拉遊戲</color>對吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그 분이라면 절대 아무렇게나 던진 말은 아닐 겁니다.","JPN":"あの方のことですから、きっと無意味なことは言っていないはずです。","ENG":"She would never say such a thing without meaning it.","TWN":"如果是她，肯定不是隨口說說而已。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"아군도 아닌데 확신하는 이유는?","JPN":"味方でもないのに、そう確信する理由は？","ENG":"She's not our ally. What makes you so sure?","TWN":"她又不是我們這邊的，你為什麼這麼篤定？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"직감상 적이었으면 저희는 이미 죽었을 테니까요.","JPN":"直感です。もし敵だったら、僕たちはすでに殺されているでしょうからね。","ENG":"If she was our enemy, we would be long gone by now.","TWN":"直覺，如果她是敵人，那我們早就死了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"서윤 양은 직접 마주쳐 보셨죠? 그럼 제 말을 이해해 주실 거라고 믿습니다.","JPN":"シズカさんは直接対面したんですよね？　ならば、僕の言っていることが理解できると思います。","ENG":"You saw her, Seo Yoon. I assume you understand what I'm talking about.","TWN":"徐芸你也直接面對過她吧？那我相信你能理解我的意思。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"……그렇긴 하네. 인정하긴 싫지만서도.","JPN":"……そうね。認めたくはないけど。","ENG":"...Fair enough. Although I don't want to admit so.","TWN":"……確實如此，雖然我不想承認。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"좋아. 확인하러 가자.","JPN":"よし、確認しに行こう。","ENG":"Okay, then. Let's go and see what's over there.","TWN":"好，去確認一下吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"이제는 뭐가 나타나도 놀라지 않을 것 같으니까.","JPN":"もう何が現れたって驚かない気がするし。","ENG":"I don't think anything could surprise me anymore.","TWN":"現在不管出現什麼，都不會再讓我吃驚了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"여기는…….","JPN":"ここは……","ENG":"This...","TWN":"這裡是……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"도시네요. 성벽의 상태를 봐선 큰 전투가 벌어졌던 모양입니다.","JPN":"街ですね。城壁の状態から見て、大きな戦闘があったようです。","ENG":"It's a city. Judging from the walls, there must have been a big battle going on.","TWN":"是個城市。從城牆的狀態來看，好像發生過大規模戰鬥。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"혹시 다른 사람들이 우리보다 먼저 여기 온 거 아닐까?","JPN":"私たちより先にここに来た人がいたんじゃない？","ENG":"Do you think the others got here before us?","TWN":"你是說有其他人先我們一步來過這裡嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"아뇨. 그렇다기에는 시신이나 버려진 무기도 없는 점이 신경 쓰여요.","JPN":"いいえ。そう考えるには、死体とか捨てられた武器がなければおかしいです。","ENG":"No. It’s too desolate. No bodies, no weapons.","TWN":"不會。如果是那樣，沒有屍體或被丟棄的武器，這二點就說不通。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"오래 전에 버려진 곳 같은데. 왠지 분위기도 으스스해.","JPN":"長い間放置されていたようだけど、何だか不気味な雰囲気ね。","ENG":"This place must have been abandoned a long time ago. It feels creepy, even.","TWN":"這個地方好像很久以前就廢棄了。不知道為什麼，氣氛也很陰森。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"기분 탓만은…… 아닌 것 같네요.","JPN":"ただの気のせいでは……ないようですね。","ENG":"I think it’s more than just a hunch you're feeling.","TWN":"似乎……不只是心情的緣故。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"선배도 알아챘구나. 역시 예리하네.","JPN":"先輩も気づいていたんだ。流石の察知力ね。","ENG":"You felt it too, Shiyoon? Sharp, as always.","TWN":"前輩也發現了啊，和往常一樣敏銳呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하, 과찬입니다. 서윤 양.","JPN":"ハハ、それほどでもありませんよ、シズカさん。","ENG":"Ha ha. Very flattered, Seo Yoon.","TWN":"哈哈，你過獎了，徐芸。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"둘이서 지금 무슨 얘기를 하는 거야?","JPN":"二人で、何の話？","ENG":"What are you two talking about?","TWN":"你們二個在說什麼呢？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"별거 아닙니다. 어떤 분께서 저희 뒤를 따라오고 계시거든요.","JPN":"大したことではありません。ただ誰かに後をつけられているなと。","ENG":"Oh, nothing. It's just that we're being followed by someone.","TWN":"沒什麼。只不過有人正跟在我們後面罷了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐……? 그게 정말이야?","JPN":"え……？　本当？","ENG":"What...? Really?","TWN":"什麼……？真的嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"네. 도시에 들어설 때부터 진한 시선이 계속 느껴지더군요.","JPN":"はい。街に入った瞬間からこちらを見つめる強い視線をずっと感じていたんです。","ENG":"Yes. I sensed an intense gaze as soon as we entered this city.","TWN":"嗯，從我們進入城市開始，就一直感受到了強烈的目光。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"묘하게 익숙하면서도 껄끄럽다고 해야 할까요?","JPN":"妙に馴染みがあって、でも嫌な感じがするといいましょうか？","ENG":"It's somewhat familiar and discomforting at the same time.","TWN":"應該說莫名地熟悉又很違和嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그러니까 신호 주면 바로 움직일 수 있게 준비해.","JPN":"だから、合図したらすぐに動けるようにしておいて。","ENG":"Be ready to move at my signal.","TWN":"所以準備好，我發出訊號後就立刻行動。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"지금 우린 적진 한복판에서 조난당한 거야. 이번에도 상대가 호의적일 거란 기대는 버려.","JPN":"私たちは今、敵陣のど真ん中で遭難しているの。今回も相手が好意的だなんて期待しない方がいいわ。","ENG":"We're lost, right at the heart of the enemy's base. Don't assume that our stalker is going to be friendly this time.","TWN":"這裡大概是敵營的中央，不要抱有太大的期望，以為對方會充滿善意。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"……알고 있어.","JPN":"……わかってる。","ENG":"...I know.","TWN":"……我知道。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"저 모퉁이를 지났을 때 바로 제압하는 거야.","JPN":"あの角を曲がった瞬間に制圧しよう。","ENG":"We act right when we pass that corner over there.","TWN":"經過那個拐角，出其不意地制伏他。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"하나, 둘……","JPN":"せー、の……","ENG":"One, two...","TWN":"三，二，一……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"지금!","JPN":"今よっ！","ENG":"Now!","TWN":"就是現在！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};